18	interface ThreadTerminalState {
19	  terminalOpen: boolean;
20	  terminalHeight: number;
21	  terminalIds: string[];
22	  runningTerminalIds: string[];
23	  activeTerminalId: string;
24	  terminalGroups: ThreadTerminalGroup[];
25	  activeTerminalGroupId: string;
26	}
