30	function normalizeTerminalIds(terminalIds: string[]): string[] {
31	  const ids = [...new Set(terminalIds.map((id) => id.trim()).filter((id) => id.length > 0))].slice(
32	    0,
33	    MAX_THREAD_TERMINAL_COUNT,
34	  );
35	  return ids.length > 0 ? ids : [DEFAULT_THREAD_TERMINAL_ID];
36	}
37	
38	function normalizeRunningTerminalIds(runningTerminalIds: string[], terminalIds: string[]): string[] {
39	  if (runningTerminalIds.length === 0) return [];
40	  const validTerminalIdSet = new Set(terminalIds);
41	  return [...new Set(runningTerminalIds)]
42	    .map((id) => id.trim())
43	    .filter((id) => id.length > 0 && validTerminalIdSet.has(id));
44	}
45	
46	function fallbackGroupId(terminalId: string): string {
47	  return `group-${terminalId}`;
48	}
49	
50	function assignUniqueGroupId(baseId: string, usedGroupIds: Set<string>): string {
51	  let candidate = baseId;
52	  let index = 2;
53	  while (usedGroupIds.has(candidate)) {
54	    candidate = `${baseId}-${index}`;
55	    index += 1;
56	  }
57	  usedGroupIds.add(candidate);
58	  return candidate;
59	}
60	
61	function findGroupIndexByTerminalId(terminalGroups: ThreadTerminalGroup[], terminalId: string): number {
62	  return terminalGroups.findIndex((group) => group.terminalIds.includes(terminalId));
63	}
64	
65	function normalizeTerminalGroupIds(terminalIds: string[]): string[] {
66	  return [...new Set(terminalIds.map((id) => id.trim()).filter((id) => id.length > 0))];
67	}
68	
69	function normalizeTerminalGroups(
70	  terminalGroups: ThreadTerminalGroup[],
71	  terminalIds: string[],
72	): ThreadTerminalGroup[] {
73	  const validTerminalIdSet = new Set(terminalIds);
74	  const assignedTerminalIds = new Set<string>();
75	  const nextGroups: ThreadTerminalGroup[] = [];
76	  const usedGroupIds = new Set<string>();
77	
78	  for (const group of terminalGroups) {
79	    const groupTerminalIds = normalizeTerminalGroupIds(group.terminalIds).filter((terminalId) => {
80	      if (!validTerminalIdSet.has(terminalId)) return false;
81	      if (assignedTerminalIds.has(terminalId)) return false;
82	      return true;
83	    });
84	    if (groupTerminalIds.length === 0) continue;
85	    for (const terminalId of groupTerminalIds) {
86	      assignedTerminalIds.add(terminalId);
87	    }
88	    const baseGroupId =
89	      group.id.trim().length > 0
90	        ? group.id.trim()
91	        : fallbackGroupId(groupTerminalIds[0] ?? DEFAULT_THREAD_TERMINAL_ID);
92	    nextGroups.push({
93	      id: assignUniqueGroupId(baseGroupId, usedGroupIds),
94	      terminalIds: groupTerminalIds,
95	    });
96	  }
97	
98	  for (const terminalId of terminalIds) {
99	    if (assignedTerminalIds.has(terminalId)) continue;
100	    nextGroups.push({
101	      id: assignUniqueGroupId(fallbackGroupId(terminalId), usedGroupIds),
102	      terminalIds: [terminalId],
103	    });
104	  }
105	
106	  if (nextGroups.length === 0) {
107	    return [
108	      {
109	        id: fallbackGroupId(DEFAULT_THREAD_TERMINAL_ID),
110	        terminalIds: [DEFAULT_THREAD_TERMINAL_ID],
111	      },
112	    ];
113	  }
114	
115	  return nextGroups;
116	}
117	
118	function arraysEqual(a: string[], b: string[]): boolean {
119	  if (a.length !== b.length) return false;
120	  for (let index = 0; index < a.length; index += 1) {
121	    if (a[index] !== b[index]) return false;
122	  }
123	  return true;
124	}
125	
126	function terminalGroupsEqual(left: ThreadTerminalGroup[], right: ThreadTerminalGroup[]): boolean {
127	  if (left.length !== right.length) return false;
128	  for (let index = 0; index < left.length; index += 1) {
129	    const leftGroup = left[index];
130	    const rightGroup = right[index];
131	    if (!leftGroup || !rightGroup) return false;
132	    if (leftGroup.id !== rightGroup.id) return false;
133	    if (!arraysEqual(leftGroup.terminalIds, rightGroup.terminalIds)) return false;
134	  }
135	  return true;
136	}
137	
138	function threadTerminalStateEqual(left: ThreadTerminalState, right: ThreadTerminalState): boolean {
139	  return (
140	    left.terminalOpen === right.terminalOpen &&
141	    left.terminalHeight === right.terminalHeight &&
142	    left.activeTerminalId === right.activeTerminalId &&
143	    left.activeTerminalGroupId === right.activeTerminalGroupId &&
144	    arraysEqual(left.terminalIds, right.terminalIds) &&
145	    arraysEqual(left.runningTerminalIds, right.runningTerminalIds) &&
146	    terminalGroupsEqual(left.terminalGroups, right.terminalGroups)
147	  );
148	}
149	
150	const DEFAULT_THREAD_TERMINAL_STATE: ThreadTerminalState = Object.freeze({
151	  terminalOpen: false,
152	  terminalHeight: DEFAULT_THREAD_TERMINAL_HEIGHT,
153	  terminalIds: [DEFAULT_THREAD_TERMINAL_ID],
154	  runningTerminalIds: [],
155	  activeTerminalId: DEFAULT_THREAD_TERMINAL_ID,
156	  terminalGroups: [
157	    {
158	      id: fallbackGroupId(DEFAULT_THREAD_TERMINAL_ID),
159	      terminalIds: [DEFAULT_THREAD_TERMINAL_ID],
160	    },
161	  ],
162	  activeTerminalGroupId: fallbackGroupId(DEFAULT_THREAD_TERMINAL_ID),
163	});
164	
165	function createDefaultThreadTerminalState(): ThreadTerminalState {
166	  return {
167	    ...DEFAULT_THREAD_TERMINAL_STATE,
168	    terminalIds: [...DEFAULT_THREAD_TERMINAL_STATE.terminalIds],
169	    runningTerminalIds: [...DEFAULT_THREAD_TERMINAL_STATE.runningTerminalIds],
170	    terminalGroups: copyTerminalGroups(DEFAULT_THREAD_TERMINAL_STATE.terminalGroups),
171	  };
172	}
173	
174	function getDefaultThreadTerminalState(): ThreadTerminalState {
175	  return DEFAULT_THREAD_TERMINAL_STATE;
176	}
177	
178	function normalizeThreadTerminalState(state: ThreadTerminalState): ThreadTerminalState {
179	  const terminalIds = normalizeTerminalIds(state.terminalIds);
180	  const nextTerminalIds = terminalIds.length > 0 ? terminalIds : [DEFAULT_THREAD_TERMINAL_ID];
181	  const runningTerminalIds = normalizeRunningTerminalIds(state.runningTerminalIds, nextTerminalIds);
182	  const activeTerminalId = nextTerminalIds.includes(state.activeTerminalId)
183	    ? state.activeTerminalId
184	    : (nextTerminalIds[0] ?? DEFAULT_THREAD_TERMINAL_ID);
185	  const terminalGroups = normalizeTerminalGroups(state.terminalGroups, nextTerminalIds);
186	  const activeGroupIdFromState = terminalGroups.some((group) => group.id === state.activeTerminalGroupId)
187	    ? state.activeTerminalGroupId
188	    : null;
189	  const activeGroupIdFromTerminal =
190	    terminalGroups.find((group) => group.terminalIds.includes(activeTerminalId))?.id ?? null;
191	
192	  const normalized: ThreadTerminalState = {
193	    terminalOpen: state.terminalOpen,
194	    terminalHeight:
195	      Number.isFinite(state.terminalHeight) && state.terminalHeight > 0
196	        ? state.terminalHeight
197	        : DEFAULT_THREAD_TERMINAL_HEIGHT,
198	    terminalIds: nextTerminalIds,
199	    runningTerminalIds,
200	    activeTerminalId,
201	    terminalGroups,
202	    activeTerminalGroupId:
203	      activeGroupIdFromState ??
204	      activeGroupIdFromTerminal ??
205	      terminalGroups[0]?.id ??
206	      fallbackGroupId(DEFAULT_THREAD_TERMINAL_ID),
207	  };
208	  return threadTerminalStateEqual(state, normalized) ? state : normalized;
209	}
210	
211	function isDefaultThreadTerminalState(state: ThreadTerminalState): boolean {
212	  const normalized = normalizeThreadTerminalState(state);
213	  return threadTerminalStateEqual(normalized, DEFAULT_THREAD_TERMINAL_STATE);
214	}
215	
216	function isValidTerminalId(terminalId: string): boolean {
217	  return terminalId.trim().length > 0;
218	}
219	
220	function copyTerminalGroups(groups: ThreadTerminalGroup[]): ThreadTerminalGroup[] {
221	  return groups.map((group) => ({
222	    id: group.id,
223	    terminalIds: [...group.terminalIds],
224	  }));
225	}
226	
227	function upsertTerminalIntoGroups(
228	  state: ThreadTerminalState,
229	  terminalId: string,
230	  mode: "split" | "new",
231	): ThreadTerminalState {
232	  const normalized = normalizeThreadTerminalState(state);
233	  if (!isValidTerminalId(terminalId)) {
234	    return normalized;
235	  }
236	
237	  const isNewTerminal = !normalized.terminalIds.includes(terminalId);
238	  if (isNewTerminal && normalized.terminalIds.length >= MAX_THREAD_TERMINAL_COUNT) {
239	    return normalized;
240	  }
241	
242	  const terminalIds = isNewTerminal ? [...normalized.terminalIds, terminalId] : normalized.terminalIds;
243	  const terminalGroups = copyTerminalGroups(normalized.terminalGroups);
244	
245	  const existingGroupIndex = findGroupIndexByTerminalId(terminalGroups, terminalId);
246	  if (existingGroupIndex >= 0) {
247	    terminalGroups[existingGroupIndex]!.terminalIds = terminalGroups[existingGroupIndex]!.terminalIds.filter(
248	      (id) => id !== terminalId,
249	    );
250	    if (terminalGroups[existingGroupIndex]!.terminalIds.length === 0) {
251	      terminalGroups.splice(existingGroupIndex, 1);
252	    }
253	  }
254	
255	  if (mode === "new") {
256	    const usedGroupIds = new Set(terminalGroups.map((group) => group.id));
257	    const nextGroupId = assignUniqueGroupId(fallbackGroupId(terminalId), usedGroupIds);
258	    terminalGroups.push({ id: nextGroupId, terminalIds: [terminalId] });
259	    return normalizeThreadTerminalState({
260	      ...normalized,
261	      terminalOpen: true,
262	      terminalIds,
263	      activeTerminalId: terminalId,
264	      terminalGroups,
265	      activeTerminalGroupId: nextGroupId,
266	    });
267	  }
268	
269	  let activeGroupIndex = terminalGroups.findIndex((group) => group.id === normalized.activeTerminalGroupId);
270	  if (activeGroupIndex < 0) {
271	    activeGroupIndex = findGroupIndexByTerminalId(terminalGroups, normalized.activeTerminalId);
272	  }
273	  if (activeGroupIndex < 0) {
274	    const usedGroupIds = new Set(terminalGroups.map((group) => group.id));
275	    const nextGroupId = assignUniqueGroupId(fallbackGroupId(normalized.activeTerminalId), usedGroupIds);
276	    terminalGroups.push({ id: nextGroupId, terminalIds: [normalized.activeTerminalId] });
277	    activeGroupIndex = terminalGroups.length - 1;
278	  }
279	
280	  const destinationGroup = terminalGroups[activeGroupIndex];
281	  if (!destinationGroup) {
282	    return normalized;
283	  }
284	
285	  if (!destinationGroup.terminalIds.includes(terminalId)) {
286	    const anchorIndex = destinationGroup.terminalIds.indexOf(normalized.activeTerminalId);
287	    if (anchorIndex >= 0) {
288	      destinationGroup.terminalIds.splice(anchorIndex + 1, 0, terminalId);
289	    } else {
290	      destinationGroup.terminalIds.push(terminalId);
291	    }
292	  }
293	
294	  return normalizeThreadTerminalState({
295	    ...normalized,
296	    terminalOpen: true,
297	    terminalIds,
298	    activeTerminalId: terminalId,
299	    terminalGroups,
300	    activeTerminalGroupId: destinationGroup.id,
301	  });
302	}
303	
304	function setThreadTerminalOpen(state: ThreadTerminalState, open: boolean): ThreadTerminalState {
305	  const normalized = normalizeThreadTerminalState(state);
306	  if (normalized.terminalOpen === open) return normalized;
307	  return { ...normalized, terminalOpen: open };
308	}
309	
310	function setThreadTerminalHeight(state: ThreadTerminalState, height: number): ThreadTerminalState {
311	  const normalized = normalizeThreadTerminalState(state);
312	  if (!Number.isFinite(height) || height <= 0 || normalized.terminalHeight === height) {
313	    return normalized;
314	  }
315	  return { ...normalized, terminalHeight: height };
316	}
317	
318	function splitThreadTerminal(state: ThreadTerminalState, terminalId: string): ThreadTerminalState {
319	  return upsertTerminalIntoGroups(state, terminalId, "split");
320	}
321	
322	function newThreadTerminal(state: ThreadTerminalState, terminalId: string): ThreadTerminalState {
323	  return upsertTerminalIntoGroups(state, terminalId, "new");
324	}
325	
326	function setThreadActiveTerminal(state: ThreadTerminalState, terminalId: string): ThreadTerminalState {
327	  const normalized = normalizeThreadTerminalState(state);
328	  if (!normalized.terminalIds.includes(terminalId)) {
329	    return normalized;
330	  }
331	  const activeTerminalGroupId =
332	    normalized.terminalGroups.find((group) => group.terminalIds.includes(terminalId))?.id ??
333	    normalized.activeTerminalGroupId;
334	  if (
335	    normalized.activeTerminalId === terminalId &&
336	    normalized.activeTerminalGroupId === activeTerminalGroupId
337	  ) {
338	    return normalized;
339	  }
340	  return {
341	    ...normalized,
342	    activeTerminalId: terminalId,
343	    activeTerminalGroupId,
344	  };
345	}
346	
347	function closeThreadTerminal(state: ThreadTerminalState, terminalId: string): ThreadTerminalState {
348	  const normalized = normalizeThreadTerminalState(state);
349	  if (!normalized.terminalIds.includes(terminalId)) {
350	    return normalized;
351	  }
352	
353	  const remainingTerminalIds = normalized.terminalIds.filter((id) => id !== terminalId);
354	  if (remainingTerminalIds.length === 0) {
355	    return createDefaultThreadTerminalState();
356	  }
357	
358	  const closedTerminalIndex = normalized.terminalIds.indexOf(terminalId);
359	  const nextActiveTerminalId =
360	    normalized.activeTerminalId === terminalId
361	      ? (remainingTerminalIds[Math.min(closedTerminalIndex, remainingTerminalIds.length - 1)] ??
362	        remainingTerminalIds[0] ??
363	        DEFAULT_THREAD_TERMINAL_ID)
364	      : normalized.activeTerminalId;
365	
366	  const terminalGroups = normalized.terminalGroups
367	    .map((group) => ({
368	      ...group,
369	      terminalIds: group.terminalIds.filter((id) => id !== terminalId),
370	    }))
371	    .filter((group) => group.terminalIds.length > 0);
372	
373	  const nextActiveTerminalGroupId =
374	    terminalGroups.find((group) => group.terminalIds.includes(nextActiveTerminalId))?.id ??
375	    terminalGroups[0]?.id ??
376	    fallbackGroupId(nextActiveTerminalId);
377	
378	  return normalizeThreadTerminalState({
379	    terminalOpen: normalized.terminalOpen,
380	    terminalHeight: normalized.terminalHeight,
381	    terminalIds: remainingTerminalIds,
382	    runningTerminalIds: normalized.runningTerminalIds.filter((id) => id !== terminalId),
383	    activeTerminalId: nextActiveTerminalId,
384	    terminalGroups,
385	    activeTerminalGroupId: nextActiveTerminalGroupId,
386	  });
387	}
388	
389	function setThreadTerminalActivity(
390	  state: ThreadTerminalState,
391	  terminalId: string,
392	  hasRunningSubprocess: boolean,
393	): ThreadTerminalState {
394	  const normalized = normalizeThreadTerminalState(state);
395	  if (!normalized.terminalIds.includes(terminalId)) {
396	    return normalized;
397	  }
398	  const alreadyRunning = normalized.runningTerminalIds.includes(terminalId);
399	  if (hasRunningSubprocess === alreadyRunning) {
400	    return normalized;
401	  }
402	  const runningTerminalIds = new Set(normalized.runningTerminalIds);
403	  if (hasRunningSubprocess) {
404	    runningTerminalIds.add(terminalId);
405	  } else {
406	    runningTerminalIds.delete(terminalId);
407	  }
408	  return { ...normalized, runningTerminalIds: [...runningTerminalIds] };
409	}
410	
411	export function selectThreadTerminalState(
412	  terminalStateByThreadId: Record<ThreadId, ThreadTerminalState>,
413	  threadId: ThreadId,
414	): ThreadTerminalState {
415	  if (threadId.length === 0) {
416	    return getDefaultThreadTerminalState();
417	  }
418	  return terminalStateByThreadId[threadId] ?? getDefaultThreadTerminalState();
419	}
420	
421	function updateTerminalStateByThreadId(
422	  terminalStateByThreadId: Record<ThreadId, ThreadTerminalState>,
423	  threadId: ThreadId,
424	  updater: (state: ThreadTerminalState) => ThreadTerminalState,
425	): Record<ThreadId, ThreadTerminalState> {
426	  if (threadId.length === 0) {
427	    return terminalStateByThreadId;
428	  }
429	
430	  const current = selectThreadTerminalState(terminalStateByThreadId, threadId);
431	  const next = updater(current);
432	  if (next === current) {
433	    return terminalStateByThreadId;
434	  }
435	
436	  if (isDefaultThreadTerminalState(next)) {
437	    if (terminalStateByThreadId[threadId] === undefined) {
438	      return terminalStateByThreadId;
439	    }
440	    const { [threadId]: _removed, ...rest } = terminalStateByThreadId;
441	    return rest as Record<ThreadId, ThreadTerminalState>;
442	  }
443	
444	  return {
445	    ...terminalStateByThreadId,
446	    [threadId]: next,
447	  };
448	}
449	
450	interface TerminalStateStoreState {
451	  terminalStateByThreadId: Record<ThreadId, ThreadTerminalState>;
452	  setTerminalOpen: (threadId: ThreadId, open: boolean) => void;
453	  setTerminalHeight: (threadId: ThreadId, height: number) => void;
454	  splitTerminal: (threadId: ThreadId, terminalId: string) => void;
455	  newTerminal: (threadId: ThreadId, terminalId: string) => void;
456	  setActiveTerminal: (threadId: ThreadId, terminalId: string) => void;
457	  closeTerminal: (threadId: ThreadId, terminalId: string) => void;
458	  setTerminalActivity: (
459	    threadId: ThreadId,
460	    terminalId: string,
461	    hasRunningSubprocess: boolean,
462	  ) => void;
463	  clearTerminalState: (threadId: ThreadId) => void;
464	  removeOrphanedTerminalStates: (activeThreadIds: Set<ThreadId>) => void;
465	}
466	
467	export const useTerminalStateStore = create<TerminalStateStoreState>()(
468	  persist(
469	    (set) => {
470	      const updateTerminal = (
471	        threadId: ThreadId,
472	        updater: (state: ThreadTerminalState) => ThreadTerminalState,
473	      ) => {
474	        set((state) => {
475	          const nextTerminalStateByThreadId = updateTerminalStateByThreadId(
476	            state.terminalStateByThreadId,
477	            threadId,
478	            updater,
479	          );
480	          if (nextTerminalStateByThreadId === state.terminalStateByThreadId) {
481	            return state;
482	          }
483	          return {
484	            terminalStateByThreadId: nextTerminalStateByThreadId,
485	          };
486	        });
487	      };
488	
489	      return {
490	        terminalStateByThreadId: {},
491	        setTerminalOpen: (threadId, open) =>
492	          updateTerminal(threadId, (state) => setThreadTerminalOpen(state, open)),
493	        setTerminalHeight: (threadId, height) =>
494	          updateTerminal(threadId, (state) => setThreadTerminalHeight(state, height)),
495	        splitTerminal: (threadId, terminalId) =>
496	          updateTerminal(threadId, (state) => splitThreadTerminal(state, terminalId)),
497	        newTerminal: (threadId, terminalId) =>
498	          updateTerminal(threadId, (state) => newThreadTerminal(state, terminalId)),
499	        setActiveTerminal: (threadId, terminalId) =>
500	          updateTerminal(threadId, (state) => setThreadActiveTerminal(state, terminalId)),
501	        closeTerminal: (threadId, terminalId) =>
502	          updateTerminal(threadId, (state) => closeThreadTerminal(state, terminalId)),
503	        setTerminalActivity: (threadId, terminalId, hasRunningSubprocess) =>
504	          updateTerminal(threadId, (state) =>
505	            setThreadTerminalActivity(state, terminalId, hasRunningSubprocess),
506	          ),
507	        clearTerminalState: (threadId) =>
508	          updateTerminal(threadId, () => createDefaultThreadTerminalState()),
509	        removeOrphanedTerminalStates: (activeThreadIds) =>
510	          set((state) => {
511	            const orphanedIds = Object.keys(state.terminalStateByThreadId).filter(
512	              (id) => !activeThreadIds.has(id as ThreadId),
513	            );
514	            if (orphanedIds.length === 0) return state;
515	            const next = { ...state.terminalStateByThreadId };
516	            for (const id of orphanedIds) {
517	              delete next[id as ThreadId];
518	            }
519	            return { terminalStateByThreadId: next };
520	          }),
521	      };
522	    },
523	    {
524	      name: TERMINAL_STATE_STORAGE_KEY,
525	      version: 1,
526	      storage: createJSONStorage(() => localStorage),
527	      partialize: (state) => ({
528	        terminalStateByThreadId: state.terminalStateByThreadId,
529	      }),
530	    },
531	  ),
532	);
