110	  socket.end(
111	    `HTTP/1.1 ${statusCode} ${statusCode === 401 ? "Unauthorized" : "Bad Request"}\r\n` +
112	      "Connection: close\r\n" +
113	      "Content-Type: text/plain\r\n" +
114	      `Content-Length: ${Buffer.byteLength(message)}\r\n` +
115	      "\r\n" +
116	      message,
