120	function websocketRawToString(raw: unknown): string | null {
121	  if (typeof raw === "string") {
122	    return raw;
123	  }
124	  if (raw instanceof Uint8Array) {
125	    return Buffer.from(raw).toString("utf8");
126	  }
127	  if (raw instanceof ArrayBuffer) {
128	    return Buffer.from(new Uint8Array(raw)).toString("utf8");
129	  }
130	  if (Array.isArray(raw)) {
131	    const chunks: string[] = [];
132	    for (const chunk of raw) {
133	      if (typeof chunk === "string") {
134	        chunks.push(chunk);
135	        continue;
136	      }
137	      if (chunk instanceof Uint8Array) {
138	        chunks.push(Buffer.from(chunk).toString("utf8"));
139	        continue;
140	      }
141	      if (chunk instanceof ArrayBuffer) {
142	        chunks.push(Buffer.from(new Uint8Array(chunk)).toString("utf8"));
143	        continue;
144	      }
145	      return null;
146	    }
147	    return chunks.join("");
148	  }
149	  return null;
150	}

