78	export function normalizeCustomModelSlugs(
79	  models: Iterable<string | null | undefined>,
80	  provider: ProviderKind = "codex",
81	): string[] {
82	  const normalizedModels: string[] = [];
83	  const seen = new Set<string>();
84	  const builtInModelSlugs = BUILT_IN_MODEL_SLUGS_BY_PROVIDER[provider];
85	
86	  for (const candidate of models) {
87	    const normalized = normalizeModelSlug(candidate, provider);
88	    if (
89	      !normalized ||
90	      normalized.length > MAX_CUSTOM_MODEL_LENGTH ||
91	      builtInModelSlugs.has(normalized) ||
92	      seen.has(normalized)
93	    ) {
94	      continue;
95	    }
96	
97	    seen.add(normalized);
98	    normalizedModels.push(normalized);
99	    if (normalizedModels.length >= MAX_CUSTOM_MODEL_COUNT) {
100	      break;
101	    }
102	  }
103	
104	  return normalizedModels;
105	}
