213	export const recordStartupHeartbeat = Effect.gen(function* () {
214	  const analytics = yield* AnalyticsService;
215	  const projectionSnapshotQuery = yield* ProjectionSnapshotQuery;
216	
217	  const { threadCount, projectCount } = yield* projectionSnapshotQuery.getSnapshot().pipe(
218	    Effect.map((snapshot) => ({
219	      threadCount: snapshot.threads.length,
220	      projectCount: snapshot.projects.length,
221	    })),
222	    Effect.catch((cause) =>
223	      Effect.logWarning("failed to gather startup snapshot for telemetry", { cause }).pipe(
224	        Effect.as({
225	          threadCount: 0,
226	          projectCount: 0,
227	        }),
228	      ),
229	    ),
230	  );
231	
232	  yield* analytics.record("server.boot.heartbeat", {
