238	const makeServerProgram = (input: CliInput) =>
239	  Effect.gen(function* () {
240	    const cliConfig = yield* CliConfig;
241	    const { start, stopSignal } = yield* Server;
242	    const openDeps = yield* Open;
243	    yield* cliConfig.fixPath;
244	
245	    const config = yield* ServerConfig;
246	
247	    if (!config.devUrl && !config.staticDir) {
248	      yield* Effect.logWarning(
249	        "web bundle missing and no VITE_DEV_SERVER_URL; web UI unavailable",
250	        {
251	          hint: "Run `bun run --cwd apps/web build` or set VITE_DEV_SERVER_URL for dev mode.",
252	        },
253	      );
254	    }
255	
256	    yield* start;
257	    yield* Effect.forkChild(recordStartupHeartbeat);
258	
259	    const localUrl = `http://localhost:${config.port}`;
260	    const bindUrl =
261	      config.host && !isWildcardHost(config.host)
262	        ? `http://${formatHostForUrl(config.host)}:${config.port}`
263	        : localUrl;
264	    const { authToken, devUrl, ...safeConfig } = config;
265	    yield* Effect.logInfo("T3 Code running", {
266	      ...safeConfig,
267	      devUrl: devUrl?.toString(),
268	      authEnabled: Boolean(authToken),
269	    });
270	
271	    if (!config.noBrowser) {
272	      const target = config.devUrl?.toString() ?? bindUrl;
273	      yield* openDeps.openBrowser(target).pipe(
274	        Effect.catch(() =>
275	          Effect.logInfo("browser auto-open unavailable", {
276	            hint: `Open ${target} in your browser.`,
277	          }),
278	        ),
279	      );
280	    }
281	
282	    return yield* stopSignal;
283	  }).pipe(Effect.provide(LayerLive(input)));
