### Step 1 — `packages/shared/src/theme.ts` (new file)

Pure TypeScript; zero dependencies (no Effect, no contracts). Follows the same standalone file pattern as `packages/shared/src/git.ts`.

```ts
/** Identifier for a built-in colour theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/** The 7 semantic colour tokens every theme must define. Values are CSS colour strings. */
export interface ThemeColorTokens {
  /** Main app background */
  background: string;
  /** Primary text colour */
  foreground: string;
  /** Interactive accent / primary colour */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Code-editor area background */
  editor: string;
  /** Terminal area background */
  terminal: string;
  /** Status-bar background */
  statusBar: string;
}

export interface ThemeDefinition {
  readonly id: ThemeId;
  readonly name: string;
  readonly isDark: boolean;
  readonly colors: ThemeColorTokens;
}
```

**Built-in themes** (concrete colour values):

| Token | t3-light | t3-dark | t3-midnight |
|---|---|---|---|
| background | `#ffffff` | `#0f0f0f` | `#0d0015` |
| foreground | `#1a1a1a` | `#ededed` | `#e8dff5` |
| accent | `oklch(0.488 0.217 264)` | `oklch(0.588 0.217 264)` | `oklch(0.65 0.27 288)` |
| sidebar | `#f4f4f5` | `#161616` | `#110020` |
| editor | `#fafafa` | `#0d0d0d` | `#08000d` |
| terminal | `#f0f0f0` | `#141414` | `#0f001a` |
| statusBar | `#e4e4e7` | `#0a0a0a` | `#0a0016` |
| isDark | false | true | true |

