  "types": "./src/theme.ts",
  "import": "./src/theme.ts"
}
```

---

### Step 3 — `apps/web/src/hooks/useTheme.ts` (rewrite)

**Remove:** `"light" | "dark" | "system"` type, `systemDark` snapshot field, `window.matchMedia` listener.

**Add:** Import from `@t3tools/shared/theme`.

Key implementation points:

```ts
import { type ThemeId, BUILT_IN_THEMES, DEFAULT_THEME_ID, getThemeById } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme";  // same key; old values migrate gracefully

function getStored(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight") return raw;
  // Migrate legacy values
  if (raw === "light") return "t3-light";
  // "dark" | "system" | null | unknown → default
  return DEFAULT_THEME_ID;
}

function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  const theme = getThemeById(themeId);
  const el = document.documentElement;

  if (suppressTransitions) el.classList.add("no-transitions");

  // Toggle .dark class (drives existing Tailwind dark: utilities and CSS @variant dark)
  el.classList.toggle("dark", theme.isDark);
  // Update color-scheme for browser chrome (scrollbars, inputs)
  el.style.colorScheme = theme.isDark ? "dark" : "light";

  // Override the 7 semantic tokens via inline style (highest CSS specificity)
  el.style.setProperty("--background", theme.colors.background);
  el.style.setProperty("--foreground", theme.colors.foreground);
  el.style.setProperty("--primary",    theme.colors.accent);
  el.style.setProperty("--ring",       theme.colors.accent);
  el.style.setProperty("--sidebar",             theme.colors.sidebar);
  el.style.setProperty("--editor-background",   theme.colors.editor);
  el.style.setProperty("--terminal-background", theme.colors.terminal);
  el.style.setProperty("--status-bar",          theme.colors.statusBar);

  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    el.offsetHeight;  // force reflow
    requestAnimationFrame(() => el.classList.remove("no-transitions"));
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());
```

`getSnapshot` returns `{ themeId: ThemeId }`.  
`subscribe` only listens to `storage` events (no media query — no "system" mode).

`useTheme()` export:
```ts
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const themeId = snapshot.themeId;
  const theme = getThemeById(themeId);
  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setTheme = useCallback((next: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => { applyTheme(themeId); }, [themeId]);

  return { themeId, theme, setTheme, resolvedTheme } as const;
}
```

Note: `BUILT_IN_THEMES` is re-exported from the hook so consumers can iterate without a separate import.

