  const { themeId, setTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Colour theme">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(theme.id)}
            className={`flex w-full items-center gap-4 rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
          >
            <ThemeSwatch colors={theme.colors} selected={selected} />
            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{theme.name}</span>
            </span>
