  return (
    <div
      aria-hidden="true"
      className={`relative shrink-0 overflow-hidden rounded-md border-2 transition-colors ${
        selected ? "border-primary/50" : "border-border/50"
      }`}
      style={{ width: 72, height: 48, background: colors.background }}
    >
      {/* Sidebar strip */}
      <div style={{ position: "absolute", left: 0, top: 0, width: "22%", height: "80%", background: colors.sidebar }} />
      {/* Foreground text lines */}
      <div style={{ position: "absolute", left: "28%", top: "22%", width: "50%", height: 2, borderRadius: 1, background: colors.foreground, opacity: 0.6 }} />
      <div style={{ position: "absolute", left: "28%", top: "42%", width: "38%", height: 2, borderRadius: 1, background: colors.foreground, opacity: 0.3 }} />
      {/* Accent dot */}
      <div style={{ position: "absolute", right: "8%", bottom: "22%", width: 6, height: 6, borderRadius: "50%", background: colors.accent }} />
      {/* Status bar strip */}
      <div style={{ position: "absolute", left: 0, right: 0, bottom: 0, height: "18%", background: colors.statusBar }} />
    </div>
  );
}
```

