import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type ThemeId,
  DEFAULT_THEME_ID,
  getThemeById,
} from "@t3tools/shared/theme";

export type { ThemeId };

const STORAGE_KEY = "t3code:theme";

let listeners: Array<() => void> = [];
let lastStoredTheme: ThemeId | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

/**
 * Migrate legacy stored values to a valid ThemeId.
 * "light" → "t3-light", everything else (incl. "dark" / "system") → "t3-dark".
 */
function migrateRaw(raw: string | null): ThemeId {
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight")
    return raw;
  if (raw === "light") return "t3-light";
  // "dark", "system", or any unknown value → default dark
  return DEFAULT_THEME_ID;
}

function getStored(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return migrateRaw(raw);
}

function applyTheme(id: ThemeId, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = getThemeById(id);
  const { colors, isDark } = theme;

  // Toggle the .dark class so Tailwind dark-mode utilities keep working
  document.documentElement.classList.toggle("dark", isDark);

  // Apply theme color tokens as CSS custom properties on <html>.
  // Inline style.setProperty wins over all stylesheet rules.
  const style = document.documentElement.style;
  style.setProperty("--background", colors.background);
  style.setProperty("--foreground", colors.foreground);
  style.setProperty("--primary", colors.accent);
  style.setProperty("--ring", colors.accent);
  style.setProperty("--sidebar", colors.sidebar);
  style.setProperty("--editor-background", colors.editorBackground);
  style.setProperty("--terminal-background", colors.terminalBackground);
  style.setProperty("--status-bar", colors.statusBar);

  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeId {
  const theme = getStored();
  if (lastStoredTheme === theme) return lastStoredTheme;
  lastStoredTheme = theme;
  return theme;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((next: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return { themeId, setTheme, theme: getThemeById(themeId) } as const;
}

