import type { ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * Thin root-level component that mounts the theme subscription and ensures
 * CSS custom properties stay in sync with the persisted ThemeId.
 *
 * Place this high in the tree (e.g. inside the router Wrap) so the
 * subscription is always active.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Mounting useTheme here activates the external store subscription and
  // ensures the effect-based DOM sync runs for the root of the tree.
  useTheme();
  return <>{children}</>;
}

