import { BUILT_IN_THEMES, type ThemeDefinition } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

/** 72×48 px colour swatch showing key theme surfaces */
function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  const { colors } = theme;
  return (
    <div
      aria-hidden="true"
      style={{
        width: 72,
        height: 48,
        borderRadius: 6,
        overflow: "hidden",
        flexShrink: 0,
        border: "1px solid rgba(128,128,128,0.2)",
        display: "flex",
        flexDirection: "column",
        background: colors.background,
      }}
    >
      {/* Top row: sidebar strip + main area */}
      <div style={{ display: "flex", flex: 1 }}>
        {/* Sidebar strip */}
        <div style={{ width: 14, background: colors.sidebar }} />
        {/* Editor area */}
        <div
          style={{
            flex: 1,
            background: colors.editorBackground,
            padding: "4px 5px",
            display: "flex",
            flexDirection: "column",
            gap: 3,
          }}
        >
          {/* Simulated text lines */}
          <div
            style={{
              height: 3,
              borderRadius: 2,
              width: "70%",
              background: colors.foreground,
              opacity: 0.7,
            }}
          />
          <div
            style={{
              height: 3,
              borderRadius: 2,
              width: "50%",
              background: colors.accent,
              opacity: 0.9,
            }}
          />
          <div
            style={{
              height: 3,
              borderRadius: 2,
              width: "60%",
              background: colors.foreground,
              opacity: 0.4,
            }}
          />
        </div>
      </div>
      {/* Status bar strip */}
      <div style={{ height: 6, background: colors.statusBar }} />
    </div>
  );
}

/**
 * Radio-group of theme selection buttons with colour-swatch previews.
 * Drop this into any settings panel — it reads and writes the persisted theme.
 */
export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(theme.id)}
          >
            <ThemeSwatch theme={theme} />
            <span className="flex min-w-0 flex-1 flex-col gap-0.5">
              <span className="text-sm font-medium">{theme.label}</span>
              <span className="text-xs capitalize text-muted-foreground">
                {theme.isDark ? "Dark" : "Light"} theme
              </span>
            </span>
            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

